mapper.select:
SELECT *
FROM hf_public_report
WHERE is_deleted = 0

    AND report_type = #{query.reportType}


    AND severity = #{query.severity}


    AND verify_status = #{query.verifyStatus}


    AND process_status = #{query.processStatus}


    AND (title LIKE CONCAT('%', #{query.keyword}, '%') OR content LIKE CONCAT('%', #{query.keyword}, '%'))


    AND report_time >= #{query.startTime}


    AND report_time <= #{query.endTime}

ORDER BY create_time DESC
